#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int m, n;
        scanf("%d %d", &m, &n);
        long long f[m], sigma[m];
        for (int i = 0; i < m; i++) {
            scanf("%lld", &f[i]);
        }
        for (int i = 0; i < m; i++) {
            scanf("%lld", &sigma[i]);
        }
        long long s[m];
        for (int i = 0; i < m; i++) {
            s[i] = f[i];
        }
        for (int i = m; i <= n; i++) {
            long long temp = 0;
            for (int j = 1; j <= m; j++) {
                temp = (temp + s[(i - j) % m] * sigma[j - 1]) % MOD;
            }
            s[i % m] = temp;
        }
        printf("%lld\n", s[n % m]);
    }
    return 0;
}

