import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int m = sc.nextInt();
            int n = sc.nextInt();
            long[] f = new long[m];
            long[] sigma = new long[m];
            for (int i = 0; i < m; i++) {
                f[i] = sc.nextLong();
            }
            for (int i = 0; i < m; i++) {
                sigma[i] = sc.nextLong();
            }
            long[] s = new long[m];
            for (int i = 0; i < m; i++) {
                s[i] = f[i];
            }
            final long MOD = 1000000007;
            for (int i = m; i <= n; i++) {
                long temp = 0;
                for (int j = 1; j <= m; j++) {
                    temp = (temp + s[(i - j) % m] * sigma[j - 1]) % MOD;
                }
                s[i % m] = temp;
            }
            System.out.println(s[n % m]);
        }
    }
}

